import numpy as np
from typing import List

def random_su2(rng):
    z = rng.standard_normal((2,2)) + 1j*rng.standard_normal((2,2))
    q, r = np.linalg.qr(z)
    d = np.diag(r)
    return q @ np.diag(d/np.abs(d))

def generate_random_circuit(n_qubits: int, depth: int) -> List[dict]:
    rng = np.random.default_rng()
    cz = np.diag([1,1,1,-1])
    circuit = []
    for d in range(depth):
        layer = {'single': [(q, random_su2(rng)) for q in range(n_qubits)],
                 'two': [(i, i+1, cz) for i in range(d%2, n_qubits-1, 2)]}
        circuit.append(layer)
    return circuit

import numpy as np
from scipy import stats

def analyze_porter_thomas(distribution: np.ndarray) -> dict:
    n_qubits = int(np.log2(len(distribution)))
    scaled = distribution * (2 ** n_qubits)
    ks_stat, ks_pvalue = stats.kstest(scaled, 'expon')
    return {'n_qubits': n_qubits, 'mean_scaled': np.mean(scaled),
            'ks_pvalue': ks_pvalue, 'is_porter_thomas': ks_pvalue > 0.05}

import numpy as np

def estimate_tree_width(n_qubits: int, depth: int, connectivity: str) -> dict:
    if connectivity == 'linear': tw = min(n_qubits, 2*depth)
    elif connectivity == 'grid':
        side = int(np.ceil(np.sqrt(n_qubits)))
        tw = min(side, depth) * side
    else: tw = n_qubits - 1
    cost = (2**tw) * n_qubits * depth
    return {'tree_width': tw, 'contraction_cost': cost, 'log_cost': np.log10(cost+1)}

import numpy as np

def estimate_xeb_with_confidence(ideal: np.ndarray, n_samples: int, noise: dict = None) -> dict:
    N = len(ideal)
    n_qubits = int(np.log2(N))
    actual = ideal.copy()
    if noise:
        dep = noise.get('depolarizing', 0)
        actual = (1-dep)*ideal + dep/N
    samples = np.random.choice(N, n_samples, p=actual)
    xeb = N * np.mean(ideal[samples]) - 1
    var = np.var(ideal[samples])
    std_err = N * np.sqrt(var / n_samples)
    return {'xeb': xeb, 'std_error': std_err, 'confidence_95': (xeb-1.96*std_err, xeb+1.96*std_err)}
